// Extract content from a single bytes or URI input.
func Extract(input ExtractInput, config ExtractionConfig) (*ExtractionResult, error) {
	jsonBytescInput, err := json.Marshal(input)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescInput) == "null" {
		jsonBytescInput = []byte("{}")
	}
	tmpStrcInput := C.CString(string(jsonBytescInput))
	cInput := C.xberg_extract_input_from_json(tmpStrcInput)
	C.free(unsafe.Pointer(tmpStrcInput))
	if cInput == nil {
		return nil, fmt.Errorf("failed to create extract_input: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_extract_input_free(cInput)

	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.xberg_extraction_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return nil, fmt.Errorf("failed to create extraction_config: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_extraction_config_free(cConfig)

	ptr := C.xberg_extract(cInput, cConfig)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.xberg_extraction_result_free(ptr)
		}
		return nil, err
	}
	defer C.xberg_extraction_result_free(ptr)
	jsonPtr := C.xberg_extraction_result_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert to JSON")
	}
	defer C.xberg_free_string(jsonPtr)
	var result ExtractionResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return &result, nil
}

