// MapURL discover all pages and sitemaps reachable from `uri` without extracting document content.
//
// Builds a [`crawlberg::CrawlEngine`] from `config.crawl`, calls
// [`CrawlEngine::map`], and returns the set of discovered URLs as a
// [`crawlberg::MapResult`] (re-exported as `MapResult`).
//
// Use this when you need the URL inventory of a site before committing to
// full document extraction — e.g. to build a crawl queue or validate scope.
//
// Errors are returned when returns `Validation` if the crawl configuration fails
// validation or if the map operation itself fails.
func MapURL(uri string, config URLExtractionConfig) (*MapResult, error) {
	curi := C.CString(uri)
	defer C.free(unsafe.Pointer(curi))

	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.xberg_url_extraction_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return nil, fmt.Errorf("failed to create url_extraction_config: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_url_extraction_config_free(cConfig)

	ptr := C.xberg_map_url(curi, cConfig)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.xberg_map_result_free(ptr)
		}
		return nil, err
	}
	defer C.xberg_map_result_free(ptr)
	jsonPtr := C.xberg_map_result_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert to JSON")
	}
	defer C.xberg_free_string(jsonPtr)
	var result MapResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return &result, nil
}

// ListSupportedFormats list all supported document formats.
//
// Returns every file extension Xberg recognizes together with its
// corresponding MIME type, derived from the central format registry.
// Formats that have no registered file extension (such as source code,
// which is detected dynamically) are not included.
//
// The list is sorted alphabetically by file extension.
//
// Returns a vector of [`SupportedFormat`] entries sorted by extension.
//
// Example:
//
//	let formats = list_supported_formats();
//	assert!(!formats.is_empty());
//	assert!(formats.iter().any(|f| f.extension == "pdf"));
func ListSupportedFormats() []SupportedFormat {
	ptr := C.xberg_list_supported_formats()
	return func() []SupportedFormat {
		if ptr == nil {
			return nil
		}
		defer C.xberg_free_string(ptr)
		var result []SupportedFormat
		if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
			return nil
		}
		return result
	}()
}

