// MaxSimScore score a query against a document using ColBERT's MaxSim operator: for each
// query token vector, take the maximum dot product against any document
// token vector, then sum across query tokens.
//
// Returns `0.0` if `query` and `doc` have mismatched dimensionality, if either
// has zero tokens, or if either is not well-formed per
// [`MultiVectorEmbedding::is_well_formed`] (its `data` length does not match
// `num_tokens * dim`).
//
// Pure CPU primitive — available without ONNX Runtime.
//
// Since v5.0.0.
func MaxSimScore(query MultiVectorEmbedding, doc MultiVectorEmbedding) (float64, error) {
	jsonBytescQuery, err := json.Marshal(query)
	if err != nil {
		return 0, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescQuery) == "null" {
		jsonBytescQuery = []byte("{}")
	}
	tmpStrcQuery := C.CString(string(jsonBytescQuery))
	cQuery := C.xberg_multi_vector_embedding_from_json(tmpStrcQuery)
	C.free(unsafe.Pointer(tmpStrcQuery))
	if cQuery == nil {
		return 0, fmt.Errorf("failed to create multi_vector_embedding: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_multi_vector_embedding_free(cQuery)

	jsonBytescDoc, err := json.Marshal(doc)
	if err != nil {
		return 0, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescDoc) == "null" {
		jsonBytescDoc = []byte("{}")
	}
	tmpStrcDoc := C.CString(string(jsonBytescDoc))
	cDoc := C.xberg_multi_vector_embedding_from_json(tmpStrcDoc)
	C.free(unsafe.Pointer(tmpStrcDoc))
	if cDoc == nil {
		return 0, fmt.Errorf("failed to create multi_vector_embedding: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_multi_vector_embedding_free(cDoc)

	ptr := C.xberg_max_sim_score(cQuery, cDoc)
	return float64(ptr), nil
}

