// NeedsImageData check if image processing is needed by examining OCR and image extraction settings.
//
// Returns `true` if either OCR is enabled or image extraction is configured,
// indicating that image decompression and processing should occur.
// Returns `false` if both are disabled, allowing optimization to skip unnecessary
// image decompression for text-only extraction workflows.
//
// # Optimization Impact
// For text-only extractions (no OCR, no image extraction), skipping image
// decompression can improve CPU utilization by 5-10% by avoiding wasteful
// image I/O and processing when results won't be used.
// Returns `true` when image binary data should be extracted.
//
// True when `config.images.extract_images` is set, captioning is configured, or QR-code
// detection is enabled. Captioning and QR-code detection both require image bytes
// regardless of whether the caller also requested image extraction.
func (r *ExtractionConfig) NeedsImageData() (bool, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return false, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.xberg_extraction_config_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return false, fmt.Errorf("failed to create receiver: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_extraction_config_free(cRecv)
	ptr := C.xberg_extraction_config_needs_image_data(cRecv)
	return ptr != 0, nil
}

