// FromBytes build a bytes input with a MIME type and optional filename hint.
func ExtractInputFromBytes(bytes []byte, mimeType string, filename *string) *ExtractInput {
	var cBytes *C.uint8_t
	if len(bytes) > 0 {
		var cBytesPinner runtime.Pinner
		cBytesPinner.Pin(&bytes[0])
		defer cBytesPinner.Unpin()
		cBytes = (*C.uint8_t)(unsafe.Pointer(&bytes[0]))
	}
	cBytesLen := C.uintptr_t(len(bytes))

	cMimeType := C.CString(mimeType)
	defer C.free(unsafe.Pointer(cMimeType))

	var cFilename *C.char
	if filename != nil {
		cFilename = C.CString(*filename)
		defer C.free(unsafe.Pointer(cFilename))
	}

	ptr := C.xberg_extract_input_from_bytes(cBytes, cBytesLen, cMimeType, cFilename)
	defer C.xberg_extract_input_free(ptr)
	return func() *ExtractInput {
		jsonPtr := C.xberg_extract_input_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.xberg_free_string(jsonPtr)
		var result ExtractInput
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}()
}

