// Validate user-supplied terms and patterns at config-construction time.
//
// Compiles every [`RedactionPattern::pattern`] (with the case-insensitive
// inline flag where applicable) and returns the first compilation error so
// the caller can reject the config before the redaction pipeline runs.
// Pure terms (regex-escaped) cannot fail to compile, but the function
// still rejects empty values to avoid degenerate zero-length matches.
func (r *RedactionConfig) Validate() error {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.xberg_redaction_config_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return fmt.Errorf("failed to create receiver: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_redaction_config_free(cRecv)
	C.xberg_redaction_config_validate(cRecv)
	jsonPtrUpdated := C.xberg_redaction_config_to_json(cRecv)
	if jsonPtrUpdated != nil {
		_ = json.Unmarshal([]byte(C.GoString(jsonPtrUpdated)), r)
		C.xberg_free_string(jsonPtrUpdated)
	}
	return lastError()
}

