// IsWellFormed returns `true` if `data` holds exactly `num_tokens * dim` values — i.e.
// the flat buffer matches the declared shape.
//
// All fields are `pub` and the type is `Deserialize`, so a value coming
// from an untrusted source (FFI caller, JSON, a store row) may be
// malformed. [`max_sim_score`] guards on this so a length-mismatched
// buffer scores `0.0` rather than silently mis-scoring (a shorter `data`
// would make [`rows`](Self::rows)' `chunks_exact` drop a trailing partial
// chunk). Uses `checked_mul` so an overflowing `num_tokens * dim` is
// reported as malformed instead of wrapping.
//
// Since v5.0.0.
func (r *MultiVectorEmbedding) IsWellFormed() (bool, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return false, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.xberg_multi_vector_embedding_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return false, fmt.Errorf("failed to create receiver: %s", C.GoString(C.xberg_last_error_context()))
	}
	defer C.xberg_multi_vector_embedding_free(cRecv)
	ptr := C.xberg_multi_vector_embedding_is_well_formed(cRecv)
	return ptr != 0, nil
}

