// ParsePreset validate `raw` against the meta-schema and deserialize into a [`Preset`],
// stamping the fingerprint over the canonical file bytes.
func (h *MetaSchema) ParsePreset(path string, raw []byte) (*Preset, error) {
	cPath := C.CString(path)
	defer C.free(unsafe.Pointer(cPath))

	var cRaw *C.uint8_t
	if len(raw) > 0 {
		var cRawPinner runtime.Pinner
		cRawPinner.Pin(&raw[0])
		defer cRawPinner.Unpin()
		cRaw = (*C.uint8_t)(unsafe.Pointer(&raw[0]))
	}
	cRawLen := C.uintptr_t(len(raw))

	ptr := C.xberg_meta_schema_parse_preset((*C.XBERGMetaSchema)(unsafe.Pointer(h.ptr)), cPath, cRaw, cRawLen)
	if err := lastError(); err != nil {
		return nil, err
	}
	defer C.xberg_preset_free(ptr)
	return func() *Preset {
		jsonPtr := C.xberg_preset_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.xberg_free_string(jsonPtr)
		var result Preset
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}(), nil
}

